import{_ as n,o as a,c as e,a as l}from"./app.1d17b5cc.js";const u=JSON.parse('{"title":"mySql 关闭自启","description":"","frontmatter":{},"headers":[{"level":2,"title":"🔧 方法一：通过「服务」管理器（图形界面）","slug":"🔧-方法一-通过「服务」管理器-图形界面","link":"#🔧-方法一-通过「服务」管理器-图形界面","children":[{"level":3,"title":"✅ 关闭 MySQL 开机自启","slug":"✅-关闭-mysql-开机自启","link":"#✅-关闭-mysql-开机自启","children":[]},{"level":3,"title":"▶ 手动启动 / 停止 MySQL 服务（随时操作）","slug":"▶-手动启动-停止-mysql-服务-随时操作","link":"#▶-手动启动-停止-mysql-服务-随时操作","children":[]}]},{"level":2,"title":"💻 方法二：使用命令行（管理员权限）","slug":"💻-方法二-使用命令行-管理员权限","link":"#💻-方法二-使用命令行-管理员权限","children":[{"level":3,"title":"1. 查看 MySQL 服务名称","slug":"_1-查看-mysql-服务名称","link":"#_1-查看-mysql-服务名称","children":[]},{"level":3,"title":"2. 禁止开机自启（设为手动）","slug":"_2-禁止开机自启-设为手动","link":"#_2-禁止开机自启-设为手动","children":[]},{"level":3,"title":"3. 完全禁用（不推荐，除非确定不用）","slug":"_3-完全禁用-不推荐-除非确定不用","link":"#_3-完全禁用-不推荐-除非确定不用","children":[]},{"level":3,"title":"4. 手动启动 MySQL","slug":"_4-手动启动-mysql","link":"#_4-手动启动-mysql","children":[]},{"level":3,"title":"5. 手动停止 MySQL","slug":"_5-手动停止-mysql","link":"#_5-手动停止-mysql","children":[]}]},{"level":2,"title":"🔍 如何确认是否生效？","slug":"🔍-如何确认是否生效","link":"#🔍-如何确认是否生效","children":[]},{"level":2,"title":"✅ 推荐做法（开发场景）","slug":"✅-推荐做法-开发场景","link":"#✅-推荐做法-开发场景","children":[]},{"level":2,"title":"批处理脚本启动 / 停止 MySQL 服务","slug":"批处理脚本启动-停止-mysql-服务","link":"#批处理脚本启动-停止-mysql-服务","children":[]}],"relativePath":"SQL/mySql关闭自启.md","lastUpdated":1766048644000}'),p={name:"SQL/mySql关闭自启.md"};function r(c,s,i,o,t,b){return a(),e("div",{"data-pagefind-body":!0},[...s[0]||(s[0]=[l(`<h1 id="mysql-关闭自启" tabindex="-1">mySql 关闭自启 <a class="header-anchor" href="#mysql-关闭自启" aria-hidden="true">#</a></h1><p>在 Windows 11 上，MySQL 安装时默认会设置为 <strong>开机自动启动</strong>（作为 Windows 服务运行）。你可以通过以下方法 <strong>关闭自启动</strong>，并在需要时 <strong>手动启动或停止 MySQL 服务</strong>。</p><hr><h2 id="🔧-方法一-通过「服务」管理器-图形界面" tabindex="-1">🔧 方法一：通过「服务」管理器（图形界面） <a class="header-anchor" href="#🔧-方法一-通过「服务」管理器-图形界面" aria-hidden="true">#</a></h2><h3 id="✅-关闭-mysql-开机自启" tabindex="-1">✅ 关闭 MySQL 开机自启 <a class="header-anchor" href="#✅-关闭-mysql-开机自启" aria-hidden="true">#</a></h3><ol><li>按下 <code>Win + R</code>，输入 <code>services.msc</code>，回车。</li><li>在服务列表中找到你的 MySQL 服务（名称通常是）： <ul><li><code>MySQL84</code></li><li><code>MySQL80</code></li><li><code>MySQL57</code></li><li>或你安装时自定义的名称（如 <code>MySQL</code>）</li></ul></li><li>右键点击该服务 → <strong>属性</strong>。</li><li>在 <strong>“启动类型”</strong> 下拉菜单中，选择： <ul><li><strong>手动</strong>（推荐）→ 开机不启动，但可手动开启<br><strong>或</strong></li><li><strong>禁用</strong> → 完全禁止启动（包括手动）</li></ul></li><li>点击 <strong>应用</strong> → <strong>确定</strong>。</li></ol><blockquote><p>⚠️ 如果当前服务正在运行，建议先点击 <strong>“停止”</strong> 按钮再修改启动类型。</p></blockquote><hr><h3 id="▶-手动启动-停止-mysql-服务-随时操作" tabindex="-1">▶ 手动启动 / 停止 MySQL 服务（随时操作） <a class="header-anchor" href="#▶-手动启动-停止-mysql-服务-随时操作" aria-hidden="true">#</a></h3><ul><li>在 <code>services.msc</code> 中： <ul><li>右键 MySQL 服务 → <strong>启动</strong>（Start）</li><li>右键 → <strong>停止</strong>（Stop）</li><li>右键 → <strong>重新启动</strong>（Restart）</li></ul></li></ul><hr><h2 id="💻-方法二-使用命令行-管理员权限" tabindex="-1">💻 方法二：使用命令行（管理员权限） <a class="header-anchor" href="#💻-方法二-使用命令行-管理员权限" aria-hidden="true">#</a></h2><h3 id="_1-查看-mysql-服务名称" tabindex="-1">1. 查看 MySQL 服务名称 <a class="header-anchor" href="#_1-查看-mysql-服务名称" aria-hidden="true">#</a></h3><div class="language-cmd line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#BABED8;">sc queryex type</span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> service | findstr /i </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">mysql</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出示例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;">SERVICE_NAME: MySQL84</span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_2-禁止开机自启-设为手动" tabindex="-1">2. 禁止开机自启（设为手动） <a class="header-anchor" href="#_2-禁止开机自启-设为手动" aria-hidden="true">#</a></h3><div class="language-cmd line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#BABED8;">sc config MySQL84 start</span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> demand</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p><code>demand</code> 表示“手动启动”。<br> 注意：<code>start=</code> 后面有一个空格！</p></blockquote><h3 id="_3-完全禁用-不推荐-除非确定不用" tabindex="-1">3. 完全禁用（不推荐，除非确定不用） <a class="header-anchor" href="#_3-完全禁用-不推荐-除非确定不用" aria-hidden="true">#</a></h3><div class="language-cmd line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#BABED8;">sc config MySQL84 start</span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> disabled</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_4-手动启动-mysql" tabindex="-1">4. 手动启动 MySQL <a class="header-anchor" href="#_4-手动启动-mysql" aria-hidden="true">#</a></h3><div class="language-cmd line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#BABED8;">net start MySQL84</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_5-手动停止-mysql" tabindex="-1">5. 手动停止 MySQL <a class="header-anchor" href="#_5-手动停止-mysql" aria-hidden="true">#</a></h3><div class="language-cmd line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#BABED8;">net stop MySQL84</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p>📌 替换 <code>MySQL84</code> 为你实际的服务名。</p></blockquote><hr><h2 id="🔍-如何确认是否生效" tabindex="-1">🔍 如何确认是否生效？ <a class="header-anchor" href="#🔍-如何确认是否生效" aria-hidden="true">#</a></h2><ul><li>重启电脑后，打开任务管理器 → “服务” 标签，搜索 <code>MySQL</code>，看状态是否为“已停止”。</li><li>或运行：<div class="language-cmd line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#BABED8;">sc query MySQL84</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>查看 <code>STATE</code> 字段。</li></ul><hr><h2 id="✅-推荐做法-开发场景" tabindex="-1">✅ 推荐做法（开发场景） <a class="header-anchor" href="#✅-推荐做法-开发场景" aria-hidden="true">#</a></h2><ul><li>将启动类型设为 <strong>“手动”</strong>（<code>demand</code>）： <ul><li>开机不自动占用内存和端口</li><li>需要时手动 <code>net start MySQL84</code> 即可</li><li>不影响日常开发使用</li></ul></li></ul><hr><p>如果你以后想恢复开机自启，只需将启动类型改回 <strong>“自动”</strong>：</p><div class="language-cmd line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#BABED8;">sc config MySQL84 start</span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> auto</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或在 <code>services.msc</code> 中设置为“自动”。</p><hr><h2 id="批处理脚本启动-停止-mysql-服务" tabindex="-1">批处理脚本启动 / 停止 MySQL 服务 <a class="header-anchor" href="#批处理脚本启动-停止-mysql-服务" aria-hidden="true">#</a></h2><p>将以下代码复制到一个文本文件中，保存为 MySQL_Control.bat（注意后缀是 .bat）</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;">@echo off</span></span>
<span class="line"><span style="color:#babed8;">:: MySQL 一键启动/停止脚本（Windows）</span></span>
<span class="line"><span style="color:#babed8;">:: 自动检测服务状态并操作</span></span>
<span class="line"><span style="color:#babed8;">:: 支持常见服务名：MySQL84, MySQL80, MySQL57, MySQL</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">setlocal enabledelayedexpansion</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">:: 检查是否以管理员身份运行</span></span>
<span class="line"><span style="color:#babed8;">net session &gt;nul 2&gt;&amp;1</span></span>
<span class="line"><span style="color:#babed8;">if %errorLevel% NEQ 0 (</span></span>
<span class="line"><span style="color:#babed8;">    echo 请以管理员身份运行此脚本！</span></span>
<span class="line"><span style="color:#babed8;">    echo.</span></span>
<span class="line"><span style="color:#babed8;">    pause</span></span>
<span class="line"><span style="color:#babed8;">    exit /b</span></span>
<span class="line"><span style="color:#babed8;">)</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">:: 尝试查找 MySQL 服务（按优先级）</span></span>
<span class="line"><span style="color:#babed8;">set &quot;mysql_service=&quot;</span></span>
<span class="line"><span style="color:#babed8;">for %%s in (MySQL84 MySQL80 MySQL57 MySQL) do (</span></span>
<span class="line"><span style="color:#babed8;">    sc query &quot;%%s&quot; &gt;nul 2&gt;&amp;1</span></span>
<span class="line"><span style="color:#babed8;">    if !errorlevel! EQU 0 (</span></span>
<span class="line"><span style="color:#babed8;">        set &quot;mysql_service=%%s&quot;</span></span>
<span class="line"><span style="color:#babed8;">        goto :found</span></span>
<span class="line"><span style="color:#babed8;">    )</span></span>
<span class="line"><span style="color:#babed8;">)</span></span>
<span class="line"><span style="color:#babed8;">:found</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">if &quot;%mysql_service%&quot;==&quot;&quot; (</span></span>
<span class="line"><span style="color:#babed8;">    echo 未找到 MySQL 服务。请确认是否已安装 MySQL。</span></span>
<span class="line"><span style="color:#babed8;">    echo 常见服务名：MySQL84, MySQL80, MySQL57</span></span>
<span class="line"><span style="color:#babed8;">    pause</span></span>
<span class="line"><span style="color:#babed8;">    exit /b</span></span>
<span class="line"><span style="color:#babed8;">)</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">:: 查询当前服务状态</span></span>
<span class="line"><span style="color:#babed8;">for /f &quot;tokens=4&quot; %%a in (&#39;sc query &quot;%mysql_service%&quot; ^| findstr &quot;STATE&quot;&#39;) do set &quot;state=%%a&quot;</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">cls</span></span>
<span class="line"><span style="color:#babed8;">echo ==========================================</span></span>
<span class="line"><span style="color:#babed8;">echo   MySQL 服务控制面板</span></span>
<span class="line"><span style="color:#babed8;">echo   服务名称: %mysql_service%</span></span>
<span class="line"><span style="color:#babed8;">echo   当前状态: %state%</span></span>
<span class="line"><span style="color:#babed8;">echo ==========================================</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">if /i &quot;%state%&quot;==&quot;RUNNING&quot; (</span></span>
<span class="line"><span style="color:#babed8;">    echo.</span></span>
<span class="line"><span style="color:#babed8;">    echo [1] 停止 MySQL 服务</span></span>
<span class="line"><span style="color:#babed8;">    echo [2] 退出</span></span>
<span class="line"><span style="color:#babed8;">    choice /c 12 /m &quot;请选择操作&quot;</span></span>
<span class="line"><span style="color:#babed8;">    if errorlevel 2 exit /b</span></span>
<span class="line"><span style="color:#babed8;">    if errorlevel 1 (</span></span>
<span class="line"><span style="color:#babed8;">        net stop &quot;%mysql_service%&quot;</span></span>
<span class="line"><span style="color:#babed8;">        echo.</span></span>
<span class="line"><span style="color:#babed8;">        echo MySQL 服务已停止。</span></span>
<span class="line"><span style="color:#babed8;">    )</span></span>
<span class="line"><span style="color:#babed8;">) else (</span></span>
<span class="line"><span style="color:#babed8;">    echo.</span></span>
<span class="line"><span style="color:#babed8;">    echo [1] 启动 MySQL 服务</span></span>
<span class="line"><span style="color:#babed8;">    echo [2] 退出</span></span>
<span class="line"><span style="color:#babed8;">    choice /c 12 /m &quot;请选择操作&quot;</span></span>
<span class="line"><span style="color:#babed8;">    if errorlevel 2 exit /b</span></span>
<span class="line"><span style="color:#babed8;">    if errorlevel 1 (</span></span>
<span class="line"><span style="color:#babed8;">        net start &quot;%mysql_service%&quot;</span></span>
<span class="line"><span style="color:#babed8;">        echo.</span></span>
<span class="line"><span style="color:#babed8;">        echo MySQL 服务已启动。</span></span>
<span class="line"><span style="color:#babed8;">    )</span></span>
<span class="line"><span style="color:#babed8;">)</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;">echo.</span></span>
<span class="line"><span style="color:#babed8;">pause</span></span>
<span class="line"><span style="color:#babed8;"></span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br><span class="line-number">43</span><br><span class="line-number">44</span><br><span class="line-number">45</span><br><span class="line-number">46</span><br><span class="line-number">47</span><br><span class="line-number">48</span><br><span class="line-number">49</span><br><span class="line-number">50</span><br><span class="line-number">51</span><br><span class="line-number">52</span><br><span class="line-number">53</span><br><span class="line-number">54</span><br><span class="line-number">55</span><br><span class="line-number">56</span><br><span class="line-number">57</span><br><span class="line-number">58</span><br><span class="line-number">59</span><br><span class="line-number">60</span><br><span class="line-number">61</span><br><span class="line-number">62</span><br><span class="line-number">63</span><br><span class="line-number">64</span><br><span class="line-number">65</span><br><span class="line-number">66</span><br><span class="line-number">67</span><br><span class="line-number">68</span><br><span class="line-number">69</span><br><span class="line-number">70</span><br><span class="line-number">71</span><br><span class="line-number">72</span><br></div></div>`,40)])])}const y=n(p,[["render",r]]);export{u as __pageData,y as default};
